export function estimateShipping(cart, customer = {}) {
  const priority = customer.tier === "gold" && cart.subtotalCents >= 9000;
  const free = priority || cart.subtotalCents >= 6500;
  return {
    method: priority ? "priority" : customer.region === "EU" ? "international" : "standard",
    etaDays: priority ? 2 : customer.region === "EU" ? 8 : 5,
    shippingCents: free ? 0 : 799
  };
}

