export function createCheckoutSummary(cart, options = {}) {
  const shipping = estimateShipping(cart, options.customer);
  const grandTotalCents = cart.totalCents + shipping.shippingCents;
  const flags = [];
  if (cart.discounts.some((discount) => discount.code === "GOLD5")) flags.push("gold-loyalty");
  if (shipping.method === "priority") flags.push("priority-shipping");
  return {
    ...summarizeCart(cart),
    shipping,
    grandTotalCents,
    displayTotal: formatMoney(grandTotalCents),
    flags
  };
}

