import { createHash, randomBytes } from "node:crypto";

const orders = [];

export function placeOrder(cart, payment) {
  if (!payment?.token) throw new Error("payment token required");
  const order = {
    id: `ord_${randomBytes(6).toString("hex")}`,
    lines: cart.entries.map((entry) => ({ ...entry })),
    totalCents: cart.totalCents,
    paymentFingerprint: fingerprint(payment.token),
    status: "paid"
  };
  orders.push(order);
  return cloneOrder(order);
}

export function listOrders() {
  return orders.map(cloneOrder);
}

function fingerprint(token) {
  return createHash("sha256").update(token).digest("hex").slice(0, 12);
}

function cloneOrder(order) {
  return { ...order, lines: order.lines.map((line) => ({ ...line })) };
}
